PR #28811: Parquet reader - avoid redundant dictionary reads
Changed files (10): lib/trino-parquet/src/main/java/io/trino/parquet/predicate/PredicateUtils.java, lib/trino-parquet/src/main/java/io/trino/parquet/reader/AbstractColumnReader.java, lib/trino-parquet/src/main/java/io/trino/parquet/reader/ColumnReader.java, lib/trino-parquet/src/main/java/io/trino/parquet/reader/ParquetReader.java, lib/trino-parquet/src/main/java/io/trino/parquet/reader/RowGroupInfo.java, lib/trino-parquet/src/main/java/io/trino/parquet/writer/ParquetWriter.java, lib/trino-parquet/src/test/java/io/trino/parquet/ParquetTestUtils.java, lib/trino-parquet/src/test/java/io/trino/parquet/crypto/TestParquetEncryption.java, lib/trino-parquet/src/test/java/io/trino/parquet/reader/TestParquetReaderDictionaryFiltering.java, plugin/trino-redshift/src/main/java/io/trino/plugin/redshift/RedshiftPageSourceProvider.java
